// ═══════════════════════════════════════════════════════════════════════════════
//  Cross-paper: sentence splitting on real content
// ═══════════════════════════════════════════════════════════════════════════════

describe('sentence splitting on real extracted text', () => {
  it('paper_p1: reading order produces multiple coherent text chunks', () => {
    const { entries, width, height } = loadPage('paper_p1');
    const filtered = filterNonBodyItems(entries, width, height);
    const sorted = filtered; // stream order

    // Build the full concatenated text as our code would
    const fullText = sorted
      .map((e) => e.item.str)
      .join(' ')
      .replace(/\s+/g, ' ');

    // Should have substantial text
    expect(fullText.length).toBeGreaterThan(500);
    // Title, abstract and intro should all be present
    expect(fullText).toContain('Careful Examination');
    expect(fullText).toContain('Abstract');
    expect(fullText).toContain('Introduction');
    // Multiple sentence-ending periods
    const periodCount = (fullText.match(/\.\s/g) || []).length;
    expect(periodCount).toBeGreaterThan(5);
  });

  it('arxiv_p12: text flows from references to section content', () => {
    const { entries, width, height } = loadPage('arxiv_p12');
    const filtered = filterNonBodyItems(entries, width, height);
    const sorted = filtered; // stream order

    const fullText = sorted
      .map((e) => e.item.str)
      .join(' ')
      .replace(/\s+/g, ' ');

    // References should appear before the Resources section
    expect(fullText.indexOf('[44]')).toBeLessThan(fullText.indexOf('Resources'));
    expect(fullText.indexOf('Resources')).toBeLessThan(fullText.indexOf('Organizing team'));
  });

  it('math151_p12: does not merge section header with body into run-on', () => {
    const { entries, width, height } = loadPage('math151_p12');
    const filtered = filterNonBodyItems(entries, width, height);
    const sorted = filtered; // stream order

    // Check that "How to count" appears as distinct text, not merged with surrounding
    const howToCount = sorted.find((e) => e.item.str.includes('How to count'));
    expect(howToCount).toBeDefined();
  });
});
